def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = -np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 100.0
        elif ratio < 0.2:
            score += 1 / (0.2 - ratio + 1e-12)
            for k in range(1, 6):
                if k % 2 == 0:
                    score += (ratio ** k) / (k + 1)
                else:
                    score -= (ratio ** k) / (k + 2)
        elif 0.2 <= ratio < 0.5:
            for a in range(3):
                for b in range(1, 4):
                    score += ((-1)**a) * (ratio ** b) / (a + b + 1)
            if capacity < item * 2:
                score *= 1.5
        elif 0.5 <= ratio <= 1:
            inv_ratio = 1 - ratio
            for n in range(1, 5):
                if n % 3 == 0:
                    score += (inv_ratio ** n) * 10
                else:
                    score += -5 * (inv_ratio ** n)
            if abs(ratio - 0.75) < 0.1:
                score += 20
            for _ in range(int(capacity//item)):
                score += 1
        else:
            penalty = 0
            for m in range(1, 5):
                penalty += (ratio ** m) * (m ** 2)
            score -= penalty * 15
            if ratio > 2:
                score -= 100
        if item > capacity:
            score -= 1000
        if i % 2 == 0:
            score *= 1.1
        else:
            score *= 0.9
        priorities[i] = score
    max_priority = np.max(priorities)
    if max_priority > 0:
        priorities = priorities / max_priority
    return priorities
